import{_ as a,o as i,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const _=JSON.parse('{"title":"2017年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2017年/核心总结.md","filePath":"01_letters/2017年/核心总结.md"}'),r={name:"01_letters/2017年/核心总结.md"};function o(n,l,s,h,u,d){return i(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="_2017年巴菲特致股东信核心总结" tabindex="-1">2017年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2017年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2017年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>每股账面价值增长23%，市场价值增长21.9%，略高于标普500的21.8%</li><li>净资产增加653亿美元，其中360亿来自运营业务，290亿来自税法改革收益</li><li>过去53年每股账面价值从19美元增至211,750美元，年复合增长率19.1%</li></ul><h2 id="重大收购与投资" tabindex="-1">重大收购与投资 <a class="header-anchor" href="#重大收购与投资" aria-label="Permalink to &quot;重大收购与投资&quot;">​</a></h2><ul><li>收购Pilot Flying J 38.6%股权（美国最大旅行中心运营商，年营收约200亿美元）</li><li>Clayton Homes收购Oakwood Homes和Harris Doyle，预计2018年现场建造量超10亿美元</li><li>Shaw Industries收购U.S. Floors，销售额达57亿美元</li><li>HomeServices收购Long and Foster等，经纪人总数达40,950人</li><li>Precision Castparts收购德国Wilhelm Schulz GmbH</li></ul><h2 id="保险业务核心" tabindex="-1">保险业务核心 <a class="header-anchor" href="#保险业务核心" aria-label="Permalink to &quot;保险业务核心&quot;">​</a></h2><ul><li>保险浮存金达1,145亿美元，创历史新高</li><li>为AIG提供200亿美元长尾损失再保险，保费102亿美元，创世界纪录</li><li>飓风损失30亿美元（税后20亿美元），但仅占净资产不到1%</li><li>连续14年承保利润后首次亏损32亿美元（税前）</li></ul><h2 id="重要理念与原则" tabindex="-1">重要理念与原则 <a class="header-anchor" href="#重要理念与原则" aria-label="Permalink to &quot;重要理念与原则&quot;">​</a></h2><ul><li><strong>收购原则</strong>：坚持5大标准（持久竞争优势、优秀管理层、良好回报率、内生增长机会、合理价格），但因市场估值过高，2017年几乎未达成独立收购</li><li><strong>反对杠杆</strong>：过去53年伯克希尔股价4次大跌（跌幅37%-59%），强调借钱买股票的危险性</li><li><strong>长期持有</strong>：将股票视为企业权益而非交易代码，相信留存收益会转化为资本收益</li><li><strong>资本配置</strong>：年末持有1,160亿美元现金和国库券，等待更好的投资机会</li></ul><h2 id="投资赌博终结" tabindex="-1">投资赌博终结 <a class="header-anchor" href="#投资赌博终结" aria-label="Permalink to &quot;投资赌博终结&quot;">​</a></h2><ul><li>十年赌约结束：标普500指数基金年均收益8.5%完胜五只对冲基金组合（最高6.5%）</li><li>关键教训：&quot;表现来来去去，费用永不动摇&quot;——过高的管理费侵蚀长期收益</li><li>债券vs股票：2012年债券收益率仅0.88%，远低于股票的隐含回报率</li><li>长期视角下，股票比债券风险更低</li></ul><h2 id="管理层变动" tabindex="-1">管理层变动 <a class="header-anchor" href="#管理层变动" aria-label="Permalink to &quot;管理层变动&quot;">​</a></h2><ul><li>Ajit Jain和Greg Abel晋升为副董事长，分别负责保险和非保险业务</li><li>伯克希尔管理团队高度自治，以主人翁心态经营业务</li></ul><h2 id="关键数据" tabindex="-1">关键数据 <a class="header-anchor" href="#关键数据" aria-label="Permalink to &quot;关键数据&quot;">​</a></h2><ul><li>非保险业务税前利润200亿美元</li><li>投资组合股息收入37亿美元</li><li>资本支出115亿美元，折旧76亿美元</li><li>最大持仓：富国银行（292亿）、苹果（282亿）、美国银行（206亿）、可口可乐（183亿）</li></ul><h2 id="股东大会" tabindex="-1">股东大会 <a class="header-anchor" href="#股东大会" aria-label="Permalink to &quot;股东大会&quot;">​</a></h2><ul><li>2018年5月5日举行，关注点从账面价值转向&quot;标准化每股盈利能力&quot;</li><li>强调对中小股东的信息公平披露原则</li></ul>',17)])])}const m=a(r,[["render",o]]);export{_ as __pageData,m as default};
